cat > /tmp/binlog-reader/BinlogReader/Program.cs << 'CSHARP'
using Microsoft.Build.Logging.StructuredLogger;

var binlogPath = args[0];
var build = BinaryLog.ReadBuild(binlogPath);

Console.WriteLine("=== BUILD ERRORS ===");
build.VisitAllChildren<Error>(error =>
{
    var project = GetParentProject(error);
    Console.WriteLine($"[{project}] {error.File}({error.LineNumber},{error.ColumnNumber}): error {error.Code}: {error.Text}");
});

Console.WriteLine("\n=== BUILD WARNINGS ===");
build.VisitAllChildren<Warning>(warning =>
{
    var project = GetParentProject(warning);
    Console.WriteLine($"[{project}] {warning.File}({warning.LineNumber},{warning.ColumnNumber}): warning {warning.Code}: {warning.Text}");
});

Console.WriteLine($"\n=== BUILD RESULT: {(build.Succeeded ? "SUCCESS" : "FAILED")} ===");

// Show project build results
Console.WriteLine("\n=== PROJECT RESULTS ===");
build.VisitAllChildren<Project>(project =>
{
    Console.WriteLine($"  {project.Name} -> Succeeded={project.Succeeded}");
});

string GetParentProject(BaseNode node)
{
    var current = node.Parent;
    while (current != null)
    {
        if (current is Project p) return p.Name;
        if (current is Target t && t.Parent is Project tp) return tp.Name;
        current = current.Parent;
    }
    return "(unknown)";
}
