cat > /tmp/binlog-reader/BinlogReader/Program.cs << 'CSHARP'
using Microsoft.Build.Logging.StructuredLogger;

var binlogPath = args[0];
var build = BinaryLog.ReadBuild(binlogPath);

Console.WriteLine("=== ALL ERRORS (with ancestry) ===");
build.VisitAllChildren<Error>(error =>
{
    var ancestry = GetAncestry(error);
    Console.WriteLine($"  Error {error.Code}: {error.Text}");
    Console.WriteLine($"    File: {error.File}:{error.LineNumber}");
    Console.WriteLine($"    In: {ancestry}");
    Console.WriteLine();
});

Console.WriteLine("=== SOURCE FILES IN BINLOG ===");
build.VisitAllChildren<SourceFile>(sf =>
{
    Console.WriteLine($"  SourceFile: {sf.Name} ({sf.GetType().Name})");
});

Console.WriteLine("\n=== ALL ITEMS ===");
build.VisitAllChildren<Item>(item =>
{
    if (item.Name != null && item.Name.Contains("Compile"))
    {
        Console.WriteLine($"  Compile Item: {item.Text}");
    }
});

Console.WriteLine("\n=== LOOKING FOR EMBEDDED FILES ===");
build.VisitAllChildren<SourceFileLine>(line =>
{
    Console.WriteLine($"  Line: {line.Text}");
});

string GetAncestry(BaseNode node)
{
    var parts = new System.Collections.Generic.List<string>();
    var current = node.Parent;
    while (current != null)
    {
        parts.Add($"{current.GetType().Name}:{current}");
        current = current.Parent;
    }
    parts.Reverse();
    return string.Join(" > ", parts);
}
