cat > /tmp/binlog-reader/BinlogReader/Program.cs << 'CSHARP'
using Microsoft.Build.Logging.StructuredLogger;

var binlogPath = args[0];
var build = BinaryLog.ReadBuild(binlogPath);

Console.WriteLine("=== ALL ERRORS (with project context) ===");
build.VisitAllChildren<Error>(error =>
{
    var project = GetParentProject(error);
    var target = GetParentTarget(error);
    Console.WriteLine($"  [{project}] (target: {target})");
    Console.WriteLine($"    {error.File}({error.LineNumber},{error.ColumnNumber}): error {error.Code}: {error.Text}");
    Console.WriteLine();
});

// Try to find the source content through the Csc task
Console.WriteLine("=== CSC TASK INPUTS ===");
build.VisitAllChildren<Task>(task =>
{
    if (task.Name == "Csc")
    {
        var proj = GetParentProject(task);
        Console.WriteLine($"  Csc in [{proj}]:");
        foreach (var child in task.Children)
        {
            if (child is Folder f && f.Name == "Parameters")
            {
                foreach (var param in f.Children)
                {
                    if (param is Property p && p.Name == "Sources")
                        Console.WriteLine($"    Sources: {p.Value}");
                }
            }
        }
    }
});

// Look at project dependency graph
Console.WriteLine("\n=== PROJECT DEPENDENCY INFO ===");
build.VisitAllChildren<Project>(proj =>
{
    Console.WriteLine($"  Project: {proj.Name}");
    proj.VisitAllChildren<Item>(item =>
    {
        if (item.Name?.Contains("ProjectReference") == true)
            Console.WriteLine($"    -> references: {item.Text}");
    });
});

string GetParentProject(BaseNode node)
{
    var current = node.Parent;
    while (current != null)
    {
        if (current is Project p) return p.Name;
        current = current.Parent;
    }
    return "(unknown)";
}

string GetParentTarget(BaseNode node)
{
    var current = node.Parent;
    while (current != null)
    {
        if (current is Target t) return t.Name;
        current = current.Parent;
    }
    return "(unknown)";
}
