using Microsoft.Build.Logging.StructuredLogger;
using Task = Microsoft.Build.Logging.StructuredLogger.Task;

var binlogPath = args[0];
var build = BinaryLog.ReadBuild(binlogPath);

// Get Csc task details (sources and references)
Console.WriteLine("=== CSC TASK DETAILS ===");
build.VisitAllChildren<Task>(task =>
{
    if (task.Name == "Csc")
    {
        var proj = GetParentProject(task);
        Console.WriteLine($"\n  Csc in [{proj}]:");

        foreach (var child in task.Children)
        {
            if (child is Folder f)
            {
                Console.WriteLine($"    Folder: {f.Name}");
                foreach (var param in f.Children)
                {
                    if (param is Property p)
                    {
                        if (p.Name == "Sources" || p.Name == "References" || p.Name == "OutputAssembly")
                            Console.WriteLine($"      {p.Name}: {p.Value}");
                    }
                    else if (param is Parameter prm)
                    {
                        if (prm.Name == "Sources" || prm.Name == "References")
                        {
                            Console.WriteLine($"      {prm.Name}:");
                            foreach (var item in prm.Children)
                                Console.WriteLine($"        - {item}");
                        }
                    }
                }
            }
        }
    }
});

// Check for MSB4181 errors (cascading from failed projects)
Console.WriteLine("\n=== ALL MESSAGES CONTAINING 'failed' ===");
build.VisitAllChildren<Message>(msg =>
{
    if (msg.Text != null && (msg.Text.Contains("failed") || msg.Text.Contains("Failed")))
    {
        var proj = GetParentProject(msg);
        Console.WriteLine($"  [{proj}] {msg.Text}");
    }
});

// Check for cascading build errors
Console.WriteLine("\n=== DEPENDENCY FAILURES ===");
build.VisitAllChildren<Target>(target =>
{
    if (target.Name == "ResolveProjectReferences" || target.Name == "GetTargetPath")
    {
        var proj = GetParentProject(target);
        foreach (var child in target.Children)
        {
            if (child is Error e)
                Console.WriteLine($"  [{proj}] target={target.Name}: {e.Text}");
        }
    }
});

// Look for the actual source file listing in Source items
Console.WriteLine("\n=== SOURCE FILES IN COMPILE ITEMS ===");
build.VisitAllChildren<AddItem>(item =>
{
    if (item.Name == "Compile")
    {
        var proj = GetParentProject(item);
        foreach (var child in item.Children)
            Console.WriteLine($"  [{proj}] Compile: {child}");
    }
});

