using Microsoft.Build.Logging.StructuredLogger;
using Task = Microsoft.Build.Logging.StructuredLogger.Task;

var binlogPath = args[0];
var build = BinaryLog.ReadBuild(binlogPath);

// List ALL embedded source files (including .cs)
Console.WriteLine("=== ALL EMBEDDED FILES ===");
var archives = build.SourceFiles;
if (archives != null)
{
    foreach (var af in archives)
    {
        var path = af.FullPath;
        if (path != null && !path.Contains("/usr/share/") && !path.Contains(".nuget"))
        {
            var textLen = af.Text?.Length ?? 0;
            Console.WriteLine($"  {path} ({textLen} chars)");
        }
    }
}

// Show source files with non-zero content
Console.WriteLine("\n=== SOURCE FILE CONTENT ===");
if (archives != null)
{
    foreach (var af in archives)
    {
        var path = af.FullPath;
        if (path != null && path.EndsWith(".cs") && !path.Contains("/usr/share/") && !path.Contains(".nuget"))
        {
            Console.WriteLine($"\n--- {path} ({af.Text?.Length ?? 0} chars) ---");
            if (!string.IsNullOrEmpty(af.Text))
                Console.WriteLine(af.Text);
            else
                Console.WriteLine("(EMPTY FILE)");
        }
    }
}

// Check Core csc result
Console.WriteLine("\n=== CSC RESULTS ===");
build.VisitAllChildren<Task>(task =>
{
    if (task.Name == "Csc")
    {
        var proj = GetParentProject(task);
        foreach (var child in task.Children)
        {
            if (child is Folder f && f.Name == "Results")
            {
                foreach (var r in f.Children)
                {
                    if (r is Property p)
                        Console.WriteLine($"  [{proj}] {p.Name} = {p.Value}");
                }
            }
        }
    }
});

// Check for Api project build issues  
Console.WriteLine("\n=== API PROJECT STATUS ===");
build.VisitAllChildren<Project>(proj =>
{
    if (proj.Name?.Contains("Api") == true)
    {
        Console.WriteLine($"  {proj.Name}: Children={proj.Children.Count}");
        foreach (var child in proj.Children)
        {
            if (child is Error e)
                Console.WriteLine($"    ERROR: {e.Code}: {e.Text}");
            else if (child is Target t)
            {
                foreach (var tc in t.Children)
                {
                    if (tc is Error te)
                        Console.WriteLine($"    [{t.Name}] ERROR: {te.Code}: {te.Text}");
                    else if (tc is Message m && m.Text?.Contains("Build") == true)
                        Console.WriteLine($"    [{t.Name}] MSG: {m.Text}");
                }
            }
        }
    }
});

