cat > /tmp/binlog-reader/BinlogReader/Program.cs << 'CSHARP'
using Microsoft.Build.Logging.StructuredLogger;
using Task = Microsoft.Build.Logging.StructuredLogger.Task;

var binlogPath = args[0];
var build = BinaryLog.ReadBuild(binlogPath);

// Check the Csc response file for Newtonsoft reference
Console.WriteLine("=== SERVICES RESPONSE FILE (searching for references) ===");
build.VisitAllChildren<Task>(task =>
{
    if (task.Name == "Csc")
    {
        var proj = GetParentProject(task);
        if (proj.Contains("Services"))
        {
            foreach (var child in task.Children)
            {
                if (child is TimedMessage tm && tm.Text != null && tm.Text.Contains("ResponseFile"))
                {
                    // Check if Newtonsoft is in references
                    Console.WriteLine($"  Contains Newtonsoft: {tm.Text.Contains("Newtonsoft")}");
                    // Extract just the /reference entries
                    var parts = tm.Text.Split(' ');
                    foreach (var p in parts)
                    {
                        if (p.StartsWith("/reference:"))
                        {
                            var refPath = p.Replace("/reference:", "");
                            var fileName = System.IO.Path.GetFileName(refPath);
                            Console.WriteLine($"    ref: {fileName}");
                        }
                    }
                }
            }
        }
    }
});

// Check all .cs files in the binlog for any content
Console.WriteLine("\n=== ALL .cs FILES IN ARCHIVE ===");
var archives = build.SourceFiles;
if (archives != null)
{
    foreach (var af in archives)
    {
        if (af.FullPath != null && af.FullPath.EndsWith(".cs"))
        {
            Console.WriteLine($"  {af.FullPath} - len={af.Text?.Length ?? 0}");
            if (af.Text != null && af.Text.Length > 0)
                Console.WriteLine($"    Content: {af.Text.Substring(0, Math.Min(200, af.Text.Length))}...");
        }
    }
}

// Check if Models.cs has content (it seemed empty)  
Console.WriteLine("\n=== AUTO-GENERATED CS FILES ===");
if (archives != null)
{
    foreach (var af in archives)
    {
        if (af.FullPath != null && af.FullPath.Contains("AssemblyInfo") && af.FullPath.EndsWith(".cs"))
        {
            Console.WriteLine($"\n  --- {af.FullPath} ---");
            Console.WriteLine(af.Text);
        }
    }
}

string GetParentProject(BaseNode node)
{
    var current = node.Parent;
    while (current != null)
    {
        if (current is Project p) return p.Name;
        current = current.Parent;
    }
    return "(unknown)";
}
